	interface UpdateBillPreference {

		String UPDATE_BILL_PREFERENCE = "/UpdateBillPreference";

		@Data
		@Builder
		@NoArgsConstructor
		@AllArgsConstructor
		@JsonNaming(SnakeUpperCaseStrategy.class)
		class Request {

			private String bpNo;

			@JsonProperty("isDNC")
			private boolean dNC;

			private AccountPreference accountPref;

			private String loggedInUser;

			private String userid;

			@JsonProperty("isCompany")
			private boolean company;

			public static Request fromMSSL(Subscription.Update.Request request) {
				return Request.builder()
					.userid(request.getUserId())
					.dNC(false)
					.company(false)
					.bpNo(request.getAccountPref().get(0).getBpNo())
					.loggedInUser(request.getLoggedInUser())
					.accountPref(AccountPreference.from(request.getAccountPref()))
					.build();
			}

			public static Request fromEBS(Subscription.Update.Request request) {
				return Request.builder()
					.userid(request.getUserId())
					.dNC(false)
					.company(false)
					.bpNo(request.getBpNo())
					.loggedInUser(request.getLoggedInUser())
					.accountPref(AccountPreference.from(request.getAccountPref()))
					.build();
			}

		}

		@Data
		@Builder
		@NoArgsConstructor
		@AllArgsConstructor
		class AccountPreference {

			@JsonProperty("Item")
			private List<Preference> preferences;

			public static AccountPreference from(List<Subscription.Update.AccountPref> accounts) {
				return AccountPreference.builder()
					.preferences(accounts.stream().map(Preference::from).toList())
					.build();
			}

		}

		@Data
		@Builder
		@NoArgsConstructor
		@AllArgsConstructor
		@JsonNaming(SnakeUpperCaseStrategy.class)
		class Preference {

			@JsonProperty("bpNo")
			private String bpNo;

			private String accNo;

			// softcopy: uPortal label: I want to receive my monthly email bill summary
			private OnOrNo emailOptin;

			// hardcopy: uPortal label: I want to optout of my monthly hardcopy bill
			private OnOrNo suppressPaperOptin;

			public static Preference from(Subscription.Update.AccountPref account) {
				return Preference.builder()
					.bpNo(account.getBpNo())
					.accNo(account.getAccountNo())
					.emailOptin(account.getEmailOption().equals("X") ? OnOrNo.ON : OnOrNo.NO)
					.suppressPaperOptin(account.getSuppressPaperOption().equals("X") ? OnOrNo.ON : OnOrNo.NO)
					.build();
			}

		}

		@Data
		@Builder
		@NoArgsConstructor
		@AllArgsConstructor
		@JsonNaming(SnakeUpperCaseStrategy.class)
		class Response {

			private String code;

			private String failMsg;

		}

	}

}

package io.spdigital.ubm.common.enums;

import com.fasterxml.jackson.annotation.JsonValue;
import jakarta.validation.constraints.NotNull;
import lombok.Getter;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpMethod;
import org.springframework.http.server.reactive.ServerHttpRequest;
import org.springframework.web.util.pattern.PathPatternParser;
import java.util.List;

@RequiredArgsConstructor
@Getter
public enum Permission {

	CUST_SEARCH("cust", List.of("/admin/customers/**", "/admin/customer/**", "/admin/bpNos/userId/**"), HttpMethod.GET),
	CUST_DELINK("cust:delink", List.of("/admin/users/delink"), null),
	CUST_PASSWORD_RESET("cust:password.reset", List.of("admin/users/forgot-password"), null),
	CUST_BP_TAG("cust:bp.tag", List.of("/admin/bpNos/**"), null),
	CUST_SUBSCRIPTION("cust:subscription", List.of("/admin/subscription"), null),
	APPROVAL("approval", List.of("/approvals/**"), null),
	TRAIL_ADMIN_AUDIT("trail:admin.audit", List.of("/trail/adminAudits"), HttpMethod.GET),
	TRAIL_METER_READ("trail:meter.read", List.of("/trail/meterReadings"), HttpMethod.GET),
	TRAIL_SUBSCRIPTION("trail:subscription", List.of("/trail/subscriptions"), HttpMethod.GET),
	// TODO API not define yet
	TRAIL_FACTSHEET("trail:factsheet", List.of("/trail/factsheet"), HttpMethod.GET),
	// TODO API not define yet
	TRAIL_METER_READ_HISTORY("trail:meter.read.history", List.of("/trail/meterReadings/histories"), null),
	REPORT_MOVEIN_RESIDENTIAL("report:movein.residential", List.of("/reports/residential/movein/**"), null),
	REPORT_MOVEIN_COMMERCIAL("report:movein.commercial", List.of("/reports/commercial/movein/**"), null),
	REPORT_MOVEOUT("report:moveout", List.of("/reports/commercial/moveout/**"), null),
	REPORT_FACTSHEET_ACK("report:factsheet.ack", List.of("/reports/factsheet/**"), null),
	REPORT_STATISTIC("report:statistic", List.of("/reports/statistic/**"), null),
	REPORT_LEAKAGE_APPEAL("report:leakage.appeal", List.of("/reports/pubConcessions/**"), null),
	MODIFY_CALENDAR("modify:calendar", List.of("/modification/holidays/**"), null),
	MODIFY_LIVECHAT("modify:livechat", List.of("/modification/liveChats/**"), null),
	MODIFY_NOTIFICATION("modify:notification", List.of("/modification/notificationBanners/**"), null),
	// TODO API not define yet
	MODIFY_BROADCAST_EMAIL("modify:broadcast.email", List.of("/modification/broadcast/emails/**"), null),
	MODIFY_TIP("modify:tip", List.of("/modification/conversationTips/**"), null);

	@JsonValue
	@NotNull(message = "Please add permission's value")
	private final String value;

	private final List<String> uris; // List of allow uris

	private final HttpMethod method; // method null will allow all http method

	private static final PathPatternParser PARSER = new PathPatternParser();

	public boolean permissionMatches(ServerHttpRequest request) {
		return uris.stream().anyMatch(uri -> PARSER.parse(uri).matches(request.getPath().pathWithinApplication()))
				&& (method == null || request.getMethod() == method);
	}

	public static Permission fromValue(String value) {
		for (Permission permission : values()) {
			if (permission.getValue().equals(value)) {
				return permission;
			}
		}
		return null;
	}

}

