import io.spdigital.ubm.exception.NotFoundException;
import io.spdigital.ubm.exception.UbmApiException;
import io.spdigital.ubm.logging.Loggable;

import java.util.Map.Entry;
import java.util.stream.Collectors;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpMethod;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.stereotype.Component;
import org.springframework.util.CollectionUtils;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.reactive.function.BodyInserters;
import org.springframework.web.reactive.function.client.WebClient;
import org.springframework.web.util.UriComponentsBuilder;
import reactor.core.publisher.Flux;
import reactor.core.publisher.Mono;

import java.util.List;
import java.util.Map;
import java.util.function.Consumer;

import static org.springframework.http.CacheControl.noCache;

@Slf4j
@Component
@RequiredArgsConstructor
class ReactiveConnectorImpl implements ReactiveConnector {

	private final ConnectionProperties props;

	private final WebClient webClient;

	private final AuthAPI authAPI;

	@Loggable
	public <T> Mono<T> reactiveGet(ConnectionProperties.Host host, String requestPath,
			Map<String, List<String>> queryParams, Map<String, String> pathParams, Class<T> responseType) {

		return this.reactiveGet(host, requestPath, queryParams, pathParams, responseType, null);

	}

	@Loggable
	public <T> Mono<T> reactiveGet(ConnectionProperties.Host host, String requestPath,
			Map<String, List<String>> queryParams, Map<String, String> pathParams, Class<T> responseType,
			Consumer<HttpHeaders> postProcessHeader) {

		ConnectionProperties.ServerConnection connection = props.getConnection(host);
		return Mono.just(connection)
			.map(c -> webClient.get()
				.uri(UriComponentsBuilder.fromUriString(props.getConnection(host).getUrl() + requestPath)
					// no need to send out null value in
					// params
					.queryParams(CollectionUtils.toMultiValueMap(queryParams.entrySet()
						.stream()
						.filter(kv -> !kv.getValue().isEmpty())
						.collect(Collectors.toMap(Entry::getKey, Entry::getValue))))
					.buildAndExpand(pathParams)
					.toUri())
				.headers(httpHeaders -> {
					if (postProcessHeader != null) {
						postProcessHeader.accept(httpHeaders);
					}
				}))
			.flatMap(requestSpec -> processConnection(connection, requestSpec).map(v -> requestSpec))
			.map(requestSpec -> requestSpec.headers(headers -> {
				if (postProcessHeader != null) {
					postProcessHeader.accept(headers);
				}
			}))
			.flatMap(req -> req.retrieve()
				.onStatus(HttpStatus.NOT_FOUND::equals, response -> response.bodyToMono(NotFoundException.class))
				.bodyToMono(responseType));

	}

	@Loggable
	public <T> Mono<T> reactivePost(ConnectionProperties.Host host, String requestPath, Object requestBody,
			Class<T> responseType) {
		return this.reactivePost(host, requestPath, requestBody, responseType, null);
	}

	@Override
	public <T> Flux<T> reactiveFluxPost(ConnectionProperties.Host host, String requestPath, Object requestBody,
			Class<T> responseType) {
		return this.reactiveFluxPost(host, requestPath, requestBody, responseType, null);
	}

	private <T> Flux<T> reactiveFluxPost(ConnectionProperties.Host host, String requestPath, Object requestBody,
			Class<T> responseType, Consumer<HttpHeaders> postProcessHeader) {
		ConnectionProperties.ServerConnection connection = props.getConnection(host);
		return Flux.just(connection)
			.map(c -> webClient.post().uri(connection.getUrl() + requestPath))
			.flatMap(requestSpec -> processConnection(connection, requestSpec).map(v -> requestSpec))
			.map(requestSpec -> requestSpec.headers(headers -> {
				if (postProcessHeader != null) {
					postProcessHeader.accept(headers);
				}
			}))
			.flatMap(req -> req.bodyValue(requestBody).retrieve().bodyToFlux(responseType));
	}

	@Loggable
	public <T> Mono<T> reactivePost(ConnectionProperties.Host host, String requestPath, Object requestBody,
			Class<T> responseType, Consumer<HttpHeaders> postProcessHeader) {
		ConnectionProperties.ServerConnection connection = props.getConnection(host);
		return Mono.just(connection)
			.map(c -> webClient.post().uri(connection.getUrl() + requestPath))
			.flatMap(requestSpec -> processConnection(connection, requestSpec).map(v -> requestSpec))
			.map(requestSpec -> requestSpec.headers(headers -> {
				if (postProcessHeader != null) {
					postProcessHeader.accept(headers);
				}
			}))
			.flatMap(req -> req.bodyValue(requestBody).retrieve().bodyToMono(responseType));
	}

	@Loggable
	public <T> Mono<T> reactiveDelete(ConnectionProperties.Host host, String requestPath, Object requestBody,
			Class<T> responseType) {
		return this.reactiveDelete(host, requestPath, requestBody, responseType, null);
	}

	@Loggable
	public <T> Mono<T> reactiveDelete(ConnectionProperties.Host host, String requestPath, Object requestBody,
			Class<T> responseType, Consumer<HttpHeaders> postProcessHeader) {
		ConnectionProperties.ServerConnection connection = props.getConnection(host);
		return Mono.just(connection)
			.map(c -> webClient.method(HttpMethod.DELETE).uri(connection.getUrl() + requestPath))
			.flatMap(requestSpec -> processConnection(connection, requestSpec).map(v -> requestSpec))
			.map(requestSpec -> requestSpec.headers(headers -> {
				if (postProcessHeader != null) {
					postProcessHeader.accept(headers);
				}
			}))
			.flatMap(req -> req.bodyValue(requestBody).retrieve().bodyToMono(responseType));
	}

	@Loggable
	public <T> Mono<T> reactiveDelete(ConnectionProperties.Host host, String requestPath,
			Map<String, List<String>> queryParams, Map<String, String> pathParams, Class<T> responseType) {

		return this.reactiveDelete(host, requestPath, queryParams, pathParams, responseType, null);

	}

	@Loggable
	public <T> Mono<T> reactiveDelete(ConnectionProperties.Host host, String requestPath,
			Map<String, List<String>> queryParams, Map<String, String> pathParams, Class<T> responseType,
			Consumer<HttpHeaders> postProcessHeader) {

		ConnectionProperties.ServerConnection connection = props.getConnection(host);
		return Mono.just(connection)
			.map(c -> webClient.delete()
				.uri(UriComponentsBuilder.fromUriString(props.getConnection(host).getUrl() + requestPath)
					.queryParams(CollectionUtils.toMultiValueMap(queryParams))
					.buildAndExpand(pathParams)
					.toUri())
				.headers(httpHeaders -> {
					if (postProcessHeader != null) {
						postProcessHeader.accept(httpHeaders);
					}
				}))
			.flatMap(requestSpec -> processConnection(connection, requestSpec).map(v -> requestSpec))
			.map(requestSpec -> requestSpec.headers(headers -> {
				if (postProcessHeader != null) {
					postProcessHeader.accept(headers);
				}
			}))
			.flatMap(req -> req.retrieve()
				.onStatus(HttpStatus.NOT_FOUND::equals, response -> response.bodyToMono(NotFoundException.class))
				.bodyToMono(responseType));

	}

	@Loggable
	public <T> Mono<T> post(ConnectionProperties.Host host, String requestPath, Object requestBody,
			Class<T> responseType, Consumer<HttpHeaders> postProcessHeader) {
		ConnectionProperties.ServerConnection connection = props.getConnection(host);
		return Mono.just(connection)
			.map(c -> webClient.post().uri(connection.getUrl() + requestPath))
			.flatMap(requestSpec -> processConnection(connection, requestSpec).map(v -> requestSpec))
			.map(requestSpec -> requestSpec.headers(headers -> {
				if (postProcessHeader != null) {
					postProcessHeader.accept(headers);
				}
			}))
			.flatMap(req -> req.bodyValue(requestBody).exchangeToMono(response -> {
				log.debug("HTTP response status code: [{}]", response.statusCode());
				return response.bodyToMono(responseType);
			})
				.doOnError(ex -> log.error("Failed HTTP POST call to [{}] due to exception [{}].",
						connection.getUrl() + "/" + requestPath, ex.getMessage())));
	}

	private Mono<WebClient.RequestHeadersSpec<?>> processConnection(ConnectionProperties.ServerConnection connection,
			WebClient.RequestHeadersSpec<?> requestSpec) {
		return Mono.just(connection)
			.filter(c -> ConnectionProperties.BasicAuthConnection.class.isAssignableFrom(c.getClass()))
			.doOnNext(c -> {
				ConnectionProperties.BasicAuthConnection auth = (ConnectionProperties.BasicAuthConnection) connection;
				requestSpec.headers(hdrs -> hdrs.setBasicAuth(auth.getUsername(), auth.getPassword()));
			})
			.switchIfEmpty(Mono.just(connection))
			.filter(c -> BearerAuthConnection.class.isAssignableFrom(c.getClass()))
			.flatMap(c -> {
				BearerAuthConnection bearerAuth = (BearerAuthConnection) c;
				return getTokenFromAuth0(bearerAuth.getAudience())
					.doOnNext(token -> requestSpec.headers(headers -> headers.setBearerAuth(token)))
					.map(t -> c);
			})
			.switchIfEmpty(Mono.just(connection))
			.doOnNext(c -> requestSpec.headers(headers -> {
				if (c.getHeaders() != null && !c.getHeaders().isEmpty()) {
					c.getHeaders().forEach(headers::add);
				}
				if (headers.getFirst(HttpHeaders.CONTENT_TYPE) == null) {
					headers.setContentType(MediaType.APPLICATION_JSON);
				}
				// response data will always stay fTh and update to date
				headers.setCacheControl(noCache());
			}))
			.map(v -> requestSpec);
	}

	public <T> Flux<T> reactiveDownloadFile(String uri, MediaType fileType, Class<T> objectClass) {
		return webClient.get().uri(uri).accept(fileType).retrieve().bodyToFlux(objectClass);
	}

	@Override
	public <T> Mono<T> reactivePut(ConnectionProperties.Host host, String requestPath, Object requestBody,
			Class<T> responseType) {
		ConnectionProperties.ServerConnection connection = props.getConnection(host);
		return Mono.just(connection)
			.map(c -> webClient.put().uri(connection.getUrl() + requestPath))
			.flatMap(requestSpec -> processConnection(connection, requestSpec).map(v -> requestSpec))
			.flatMap(req -> req.bodyValue(requestBody).retrieve().bodyToMono(responseType));
	}

	private Mono<String> getTokenFromAuth0(String audience) {
		return Mono.just(audience).map(s -> authAPI.requestToken(audience)).flatMap(authRequest -> {
			try {
				log.info("getTokenFromAuth0 for audience: {}", audience);
				return Mono.just(authRequest.execute().getBody().getAccessToken());
			}
			catch (Exception e) {
				log.error("Exception caught at getTokenFromAuth0 for audience: {}, {} ", audience, e.getMessage());
				e.printStackTrace();
				return Mono.error(new UbmApiException("", "TOKEN_RETRIEVAL_FAILED", null));
			}
		});

	}

}

