package io.spdigital.ubm.logging;

import lombok.extern.slf4j.Slf4j;
import org.reactivestreams.Publisher;
import org.springframework.core.io.buffer.DataBuffer;
import org.springframework.core.io.buffer.DataBufferUtils;
import org.springframework.http.server.reactive.ServerHttpResponse;
import org.springframework.http.server.reactive.ServerHttpResponseDecorator;
import reactor.core.publisher.Flux;
import reactor.core.publisher.Mono;

import java.nio.charset.StandardCharsets;

@Slf4j
public class ResponseLoggingDecorator extends ServerHttpResponseDecorator {

	public ResponseLoggingDecorator(ServerHttpResponse delegate) {
		super(delegate);
	}

	@Override
	public Mono<Void> writeWith(Publisher<? extends DataBuffer> body) {
		if (body instanceof Flux) {
			Flux<? extends DataBuffer> fluxBody = (Flux<? extends DataBuffer>) body;
			return super.writeWith(fluxBody.map(dataBuffer -> {
				byte[] content = new byte[dataBuffer.readableByteCount()];
				dataBuffer.read(content);
				String response = new String(content, StandardCharsets.UTF_8);
				if (response.startsWith("{\"status\":"))
					log.info("Flux Response: {}", response);
				DataBufferUtils.release(dataBuffer);
				return super.bufferFactory().wrap(content);
			}));
		}
		else if (body instanceof Mono) {
			Mono<? extends DataBuffer> monoBody = (Mono<? extends DataBuffer>) body;
			return super.writeWith(monoBody.map(dataBuffer -> {
				byte[] content = new byte[dataBuffer.readableByteCount()];
				dataBuffer.read(content);
				String response = new String(content, StandardCharsets.UTF_8);
				if (response.startsWith("{\"status\":"))
					log.info("Mono Response: {}", response);
				DataBufferUtils.release(dataBuffer);
				return super.bufferFactory().wrap(content);
			}));
		}
		else {
			String className = (body != null) ? body.getClass().getName() : "null";
			log.debug("ResponseLoggingDecorator :: class:{}", className);
		}
		return super.writeWith(body);
	}

}

