	private static final String IAM_ID = "auth0|iam123";

	// -------------------------------------------------------------------------
	// Helper builders
	// -------------------------------------------------------------------------

	private Yggdrasil.User.BPMapping buildBpMapping(Character system) {
		return Yggdrasil.User.BPMapping.builder().userId(USER_ID).bpNo(BP_NO).system(system).build();
