	private SAP.MsslResponse buildMsslResponse(String ebsAccountNo) {
		SAP.MsslResponse.BpItem msslBpItem = SAP.MsslResponse.BpItem.builder()
			.bpNo(BP_NO)
			.ebsAccountNo(ebsAccountNo)
			.build();
		SAP.MsslResponse.DetailsHolder holder = SAP.MsslResponse.DetailsHolder.builder()
			.bpItems(List.of(msslBpItem))
			.build();
		return SAP.MsslResponse.builder().holder(holder).build();
	}

	private SAP.EbsResponse buildEbsResponse(SAP.EbsResponse.BpItem bpItem) {
		SAP.EbsResponse.DetailsHolder detailsHolder = SAP.EbsResponse.DetailsHolder.builder()
			.bpItems(List.of(bpItem))
			.build();
		return SAP.EbsResponse.builder().detailsHolder(detailsHolder).build();
