	private ProfileApi.GetScopes.Response buildProfileApiResponse(String mobileNo) {
		ProfileApi.GetScopes.UserMetadata userMetadata = ProfileApi.GetScopes.UserMetadata.builder()
			.number(mobileNo)
			.build();
		ProfileApi.GetScopes.Users user = ProfileApi.GetScopes.Users.builder().userMetadata(userMetadata).build();
		return ProfileApi.GetScopes.Response.builder().users(List.of(user)).build();
