	// -------------------------------------------------------------------------
	// Happy-path tests
	// -------------------------------------------------------------------------

	@Test
	@SuppressWarnings("unchecked")
	void getCustomer_happyPath_EbsSystem_returnsFullResponse() {
		Yggdrasil.User.BPMapping bpMapping = buildBpMapping('E');
		Yggdrasil.User.YD.Detail ydDetail = buildYdDetailWithIam();
		SAP.EbsResponse.BpItem ebsBpItem = buildEbsBpItem();
		Yggdrasil.User.YD.Detail[] userArray = { ydDetail };
		ProfileApi.GetScopes.Response profileApiResp = buildProfileApiResponse("91234567");

		// getBpMappingByUserIdAndBpNo
		when(reactiveConnector.reactivePost(eq(YGGDRASIL), eq(Yggdrasil.GET_BP_MAPPING_BY_USERID_AND_BPNO), any(),
				eq(Yggdrasil.User.BPMapping.class)))
			.thenReturn(Mono.just(bpMapping));

		// getEAccountDetails: GET_CP_BY_USER_ID_WITH_IAM (called twice due to dual
		// subscription)
		when(reactiveConnector.reactivePost(eq(YGGDRASIL), eq(Yggdrasil.GET_CP_BY_USER_ID_WITH_IAM), any(),
				eq(Yggdrasil.User.YD.Detail.class)))
			.thenReturn(Mono.just(ydDetail));

		// getUtilityAccDetails EBS: CUSTOMER_PROFILE_RETRIEVAL
		when(sapService.reactivePost(eq(SAP.CUSTOMER_PROFILE_RETRIEVAL), any(), eq(SAP.EbsResponse.BpItem.class)))
