		// getUtilityAccDetails: GET_USER_BY_BP_NO
		when(reactiveConnector.reactivePost(eq(YGGDRASIL), eq(Yggdrasil.GET_USER_BY_BP_NO), any(),
				eq(Yggdrasil.User.YD.Detail[].class)))
			.thenReturn(Mono.just(userArray));

		// getUtilityAccDetails: CUSTOMER_PROFILE_RETRIEVAL is eagerly evaluated as
