import static org.springframework.http.CacheControl.noCache;

@Slf4j
@Component
@RequiredArgsConstructor
class ReactiveConnectorImpl implements ReactiveConnector {

	private final ConnectionProperties props;

	private final WebClient webClient;

	private final AuthAPI authAPI;

	@Loggable
	public <T> Mono<T> reactiveGet(ConnectionProperties.Host host, String requestPath,
			Map<String, List<String>> queryParams, Map<String, String> pathParams, Class<T> responseType) {

		return this.reactiveGet(host, requestPath, queryParams, pathParams, responseType, null);

	}

	@Loggable
	public <T> Mono<T> reactiveGet(ConnectionProperties.Host host, String requestPath,
			Map<String, List<String>> queryParams, Map<String, String> pathParams, Class<T> responseType,
			Consumer<HttpHeaders> postProcessHeader) {

		ConnectionProperties.ServerConnection connection = props.getConnection(host);
		return Mono.just(connection)
			.map(c -> webClient.get()
				.uri(UriComponentsBuilder.fromUriString(props.getConnection(host).getUrl() + requestPath)
					// no need to send out null value in
					// params
					.queryParams(CollectionUtils.toMultiValueMap(queryParams.entrySet()
						.stream()
						.filter(kv -> !kv.getValue().isEmpty())
						.collect(Collectors.toMap(Entry::getKey, Entry::getValue))))
					.buildAndExpand(pathParams)
					.toUri())
				.headers(httpHeaders -> {
					if (postProcessHeader != null) {
						postProcessHeader.accept(httpHeaders);
					}
				}))
			.flatMap(requestSpec -> processConnection(connection, requestSpec).map(v -> requestSpec))
			.map(requestSpec -> requestSpec.headers(headers -> {
				if (postProcessHeader != null) {
					postProcessHeader.accept(headers);
				}
			}))
			.flatMap(req -> req.retrieve()
				.onStatus(HttpStatus.NOT_FOUND::equals, response -> response.bodyToMono(NotFoundException.class))
				.bodyToMono(responseType));

	}

	@Loggable
	public <T> Mono<T> reactivePost(ConnectionProperties.Host host, String requestPath, Object requestBody,
			Class<T> responseType) {
		return this.reactivePost(host, requestPath, requestBody, responseType, null);
