				}
			}))
			.flatMap(req -> req.bodyValue(requestBody).exchangeToMono(response -> {
				log.debug("HTTP response status code: [{}]", response.statusCode());
				return response.bodyToMono(responseType);
			})
				.doOnError(ex -> log.error("Failed HTTP POST call to [{}] due to exception [{}].",
						connection.getUrl() + "/" + requestPath, ex.getMessage())));
	}

	private Mono<WebClient.RequestHeadersSpec<?>> processConnection(ConnectionProperties.ServerConnection connection,
			WebClient.RequestHeadersSpec<?> requestSpec) {
		return Mono.just(connection)
			.filter(c -> ConnectionProperties.BasicAuthConnection.class.isAssignableFrom(c.getClass()))
			.doOnNext(c -> {
				ConnectionProperties.BasicAuthConnection auth = (ConnectionProperties.BasicAuthConnection) connection;
				requestSpec.headers(hdrs -> hdrs.setBasicAuth(auth.getUsername(), auth.getPassword()));
			})
			.switchIfEmpty(Mono.just(connection))
			.filter(c -> BearerAuthConnection.class.isAssignableFrom(c.getClass()))
			.flatMap(c -> {
				BearerAuthConnection bearerAuth = (BearerAuthConnection) c;
				return getTokenFromAuth0(bearerAuth.getAudience())
					.doOnNext(token -> requestSpec.headers(headers -> headers.setBearerAuth(token)))
					.map(t -> c);
			})
			.switchIfEmpty(Mono.just(connection))
			.doOnNext(c -> requestSpec.headers(headers -> {
				if (c.getHeaders() != null && !c.getHeaders().isEmpty()) {
					c.getHeaders().forEach(headers::add);
				}
				if (headers.getFirst(HttpHeaders.CONTENT_TYPE) == null) {
					headers.setContentType(MediaType.APPLICATION_JSON);
				}
				// response data will always stay fTh and update to date
				headers.setCacheControl(noCache());
			}))
			.map(v -> requestSpec);
	}

	public <T> Flux<T> reactiveDownloadFile(String uri, MediaType fileType, Class<T> objectClass) {
		return webClient.get().uri(uri).accept(fileType).retrieve().bodyToFlux(objectClass);
	}

	@Override
	public <T> Mono<T> reactivePut(ConnectionProperties.Host host, String requestPath, Object requestBody,
			Class<T> responseType) {
		ConnectionProperties.ServerConnection connection = props.getConnection(host);
		return Mono.just(connection)
			.map(c -> webClient.put().uri(connection.getUrl() + requestPath))
			.flatMap(requestSpec -> processConnection(connection, requestSpec).map(v -> requestSpec))
			.flatMap(req -> req.bodyValue(requestBody).retrieve().bodyToMono(responseType));
	}

	private Mono<String> getTokenFromAuth0(String audience) {
		return Mono.just(audience).map(s -> authAPI.requestToken(audience)).flatMap(authRequest -> {
			try {
				log.info("getTokenFromAuth0 for audience: {}", audience);
				return Mono.just(authRequest.execute().getBody().getAccessToken());
			}
			catch (Exception e) {
				log.error("Exception caught at getTokenFromAuth0 for audience: {}, {} ", audience, e.getMessage());
				e.printStackTrace();
				return Mono.error(new UbmApiException("", "TOKEN_RETRIEVAL_FAILED", null));
			}
		});

	}

}

