				LiveChatFeature.FF4JFeature[].class);

		return accMono.flatMapIterable(Arrays::asList)
			.doOnError(throwable -> log.error(ERROR_OCCURRED, "Fetching live chat", throwable.getMessage()))
			.onErrorResume(ex -> Mono.error(new UbmApiException(UBM_GET_LIVECHAT_ERROR_MSG, UBM_LIVECHAT_ERROR_CODE,
					"Error while fetching live chat")))
			.filter(account -> account.getUid().equalsIgnoreCase(SWITCHE_ROO_ID_OPEN_ACCOUNT)
					|| account.getUid().equalsIgnoreCase(SWITCHE_ROO_ID_CLOSE_ACCOUNT)
					|| account.getUid().equalsIgnoreCase(SWITCHE_ROO_ID_UTILITIES_PORTAL))
			.map(LiveChatUtil::convertFF4JResponse);
	}

	@Override
	public Mono<BaseResponse> updateLiveChat(String key, LiveChatFeature.LiveChatFeatureRequest request) {
		if (request.getStartDateTime().isAfter(request.getEndDateTime())) {
			throw new UbmApiException(UBM_UPDATE_LIVECHAT_INVALID_DATETIME_ERROR_MSG,
					UBM_LIVECHAT_UPDATE_INVALID_DATETIME_ERROR_CODE,
					String.format("StartDateTime:%s cannot be greater than EndDateTime:%s", request.getStartDateTime(),
							request.getEndDateTime()));
		}

		Optional<LiveChatTypeEnum> optionalKey = Arrays.stream(LiveChatTypeEnum.values())
			.filter(k -> k.name().equals(key))
			.findFirst();
		if (optionalKey.isEmpty()) {
			throw new UbmApiException(UBM_UPDATE_LIVECHAT_INVALID_ERROR_MSG, UBM_LIVECHAT_UPDATE_INVALID_KEY_ERROR_CODE,
					String.format("Invalid operational key: %s", key));
		}

		LiveChatTypeEnum opsKey = optionalKey.get();
		MultiValueMap<String, String> map = new LinkedMultiValueMap<>();
		map.add("uid", LiveChatUtil.getKey(opsKey));
		map.add("strategy", "io.spdigital.switcheroo.strategy.DownTimeStrategy");
		map.add("initParams", LiveChatUtil.prepareDownTime(request.getStartDateTime(), request.getEndDateTime()));
		map.add("op", "update");
		map.add("desc", request.getDescription());
		HttpHeaders httpHeadersSchedule = new HttpHeaders();
		httpHeadersSchedule.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
		Mono<String> postBody = reactiveConnector.reactivePost(ConnectionProperties.Host.SWITCHEROO,
				SWITCHEROO_FEATURES_API_FF4J, map, String.class, LiveChatUtil.createHeader());
		AuditRequest auditRequest = AuditRequest.builder()
			.startDateTime(request.getStartDateTime().toString())
			.endDateTime(request.getEndDateTime().toString())
			.description(request.getDescription())
			.iamId(request.getIamId())
			.build();
		return postBody.doOnError(throwable -> log.error(ERROR_OCCURRED, "Enabling live chat", throwable.getMessage()))
			.onErrorResume(ex -> {
				auditService.createAudit(
						String.format("LIVE_CHAT_%s_%s", optionalKey.get(),
								request.getToggleOn() ? Constants.ON : Constants.OFF),
						SOURCE, auditRequest, FAIL, request.getIamId(), "");
				return Mono.error(new UbmApiException(UBM_UPDATE_LIVECHAT_ERROR_MSG, UBM_UPDATE_LIVECHAT_ERROR_CODE,
						String.format("Error while enabling %s live chat", opsKey.name())));
			})
			.flatMap(response -> auditService.createAudit(
					String.format("LIVE_CHAT_%s_%s", optionalKey.get(),
							request.getToggleOn() ? Constants.ON : Constants.OFF),
					SOURCE, auditRequest, SUCCESS, request.getIamId(), ""))
			.flatMap(response -> Mono.just(BaseResponse.success()));
	}

	@Override
	public Mono<BaseResponse> toggleFeature(String operation, String key) {

		if (StringUtils.isBlank(operation)
				|| !(operation.equalsIgnoreCase("enable") || operation.equalsIgnoreCase("disable"))) {
			throw new UbmApiException(UBM_UPDATE_LIVECHAT_INVALID_ERROR_MSG, UBM_LIVECHAT_UPDATE_ENABLE_ERROR_CODE,
					String.format("Invalid operation: %s", operation));
		}

		if (StringUtils.isBlank(key)) {
			throw new UbmApiException(UBM_UPDATE_LIVECHAT_INVALID_ERROR_MSG, UBM_LIVECHAT_UPDATE_ENABLE_ERROR_CODE,
					String.format("Invalid key: %s", key));
		}

		Optional<LiveChatTypeEnum> optionalKey = Arrays.stream(LiveChatTypeEnum.values())
			.filter(k -> k.name().equals(key))
			.findFirst();
		if (optionalKey.isEmpty()) {
			throw new UbmApiException(UBM_UPDATE_LIVECHAT_INVALID_ERROR_MSG, UBM_LIVECHAT_UPDATE_ENABLE_ERROR_CODE,
					String.format("Invalid key: %s", key));
		}

		Map<String, List<String>> map = new LinkedHashMap<>();
		map.put("uid", List.of(LiveChatUtil.getKey(LiveChatTypeEnum.valueOf(key.trim()))));
		map.put("op", List.of(operation.trim()));
		return reactiveConnector
			.reactiveGet(ConnectionProperties.Host.SWITCHEROO, SWITCHEROO_FEATURES_API_FF4J, map,
					Collections.emptyMap(), String.class)
			.doOnError(throwable -> {
				log.info(throwable.getMessage());
				log.error(ERROR_OCCURRED, "Enabling live chat", throwable.getMessage());
			})
			.onErrorResume(ex -> Mono.error(new UbmApiException(UBM_UPDATE_LIVECHAT_ENABLE_ERROR_MSG,
					UBM_LIVECHAT_UPDATE_ENABLE_ERROR_CODE, String.format("Error while enabling %s live chat", key))))
			.map(res -> BaseResponse.success());
	}

