	@Override
	public Mono<Subscription.Retrieve.Response> getSubscription(Retrieve.Request request) {

		// RetrieveBillPreferenceDetails
		Mono<RetrieveBillPreferences.Response> billPreferences = sapService
			.reactivePost(RETRIEVE_BILL_PREFERENCES,
					RetrieveBillPreferences.Request.builder()
						.items(request.getAccountPrefBpNos().stream().map(RetrieveBillPreferences.BpItem::new).toList())
						.build(),
					RetrieveBillPreferences.Response.class)
			.doOnError(
					throwable -> log.warn("#getSubscription :: retrieve bill preferences :: error with userId {}:: {} ",
							request.getUserId(), throwable.getMessage()))
			.onErrorResume(ex -> Mono.error(new UbmApiException(UBM_GET_BILL_PREFERENCE_ERROR_MSG,
					UBM_GET_BILL_PREFERENCE_ERROR_CODE, "#getSubscription  :  userId:" + request.getUserId())));

		// Retrieve Accounts by bpNo to get premiseAddress
		Mono<SAP.RetrieveAccount.Response> responseAccounts = reactiveConnector
			.reactivePost(YGGDRASIL, GET_BP_MAPPING_BY_USERID_AND_BPNO,
					Yggdrasil.User.Request.builder().userId(request.getUserId()).bpNo(request.getBpNo()).build(),
					Yggdrasil.User.BPMapping.class)
			.doOnError(throwable -> log.warn(
					"#getSubscription" + " :: getBpMappingByUserIdAndBpNo :: UserId:[{}] :: Error Occurred :{}",
					request.getUserId(), throwable.getMessage()))
			.onErrorResume(ex -> Mono.error(new UbmApiException(UBM_GET_CUSTOMER_ERROR_MSG, UBM_GET_CUSTOMER_ERROR_CODE,
					String.format(BP_NO_S_USER_ID_S, request.getBpNo(), request.getUserId()))))
			.map(Yggdrasil.User.BPMapping::getSystem)
			.filter(system -> system.equals('M'))
			.flatMap(value -> retrieveAccountsByBP(request.getAccountPrefBpNos()))
			.switchIfEmpty(retrieveAccountsByBP(List.of(request.getAccountPrefBpNos().get(0))));

		return Mono.zip(billPreferences, responseAccounts)
			.map(data -> Subscription.Retrieve.Response.builder()
				.billDetails(data.getT1().getAccountPref().getAccounts().stream().flatMap(preference -> {
					if (Objects.nonNull(data.getT2().getAccountDetails())) {
						return data.getT2()
							.getAccountDetails()
							.getAccountItems()
							.stream()
							.filter(accountInfo -> accountInfo.getBpNo().equals(preference.getBpNo())
									&& accountInfo.getAccountNo().equals(preference.getAccNo()))
							.map(premise -> Subscription.Retrieve.BillDetails.builder()
								.bpNo(preference.getBpNo())
								.accountNo(preference.getAccNo())
								.isSoftCopy(preference.getEmailOptin())
								.isHardCopy(preference.getSuppressPaperOptin())
								.premiseAddress(premise.getPremiseAddress())
								.build());
					}
					else {
						return Stream.empty();
					}
				}).toList())
				.build());
	}

	@Override
	public Mono<BaseResponse> updateSubscription(Update.Request request) {
		if (StringUtils.isBlank(request.getUserId())) {
			throw new UbmApiException(UBM_SAVE_BILL_PREFERENCE_ERROR_MSG, UBM_SAVE_BILL_PREFERENCE_ERROR_CODE,
					String.format("userid cannot be blank or empty : %s ", request.getUserId()));
		}

		if (StringUtils.isBlank(request.getLoggedInUser())) {
			throw new UbmApiException(UBM_SAVE_BILL_PREFERENCE_ERROR_MSG, UBM_SAVE_BILL_PREFERENCE_ERROR_CODE,
					String.format("loggedInUser cannot be blank or empty : %s ", request.getLoggedInUser()));
		}

		if (Objects.isNull(request.getAccountPref()) || request.getAccountPref().isEmpty()) {
			throw new UbmApiException(UBM_SAVE_BILL_PREFERENCE_ERROR_MSG, UBM_SAVE_BILL_PREFERENCE_ERROR_CODE,
					"AccountPreference cannot be empty");
		}

		request.getAccountPref()
			.stream()
			.filter(req -> StringUtils.isBlank(req.getAccountNo()) || StringUtils.isBlank(req.getBpNo()))
			.findFirst()
			.ifPresent(res -> {
				throw new UbmApiException(UBM_SAVE_BILL_PREFERENCE_ERROR_MSG, UBM_SAVE_BILL_PREFERENCE_ERROR_CODE,
						"bpNo or accountNo cannot be empty");
			});

		return reactiveConnector
			.reactivePost(YGGDRASIL, GET_BP_MAPPING_BY_USERID_AND_BPNO,
					Yggdrasil.User.Request.builder().userId(request.getUserId()).bpNo(request.getBpNo()).build(),
					Yggdrasil.User.BPMapping.class)
			.doOnError(throwable -> log.error(
					"#updateSubscription :: getBpMappingByUserIdAndBpNo" + " : UserId:[{}] :: Error Occurred :{}",
					request.getUserId(), throwable.getMessage()))
			.onErrorResume(ex -> Mono.error(new UbmApiException(UBM_GET_CUSTOMER_ERROR_MSG, UBM_GET_CUSTOMER_ERROR_CODE,
					String.format(BP_NO_S_USER_ID_S, request.getBpNo(), request.getUserId()))))
			.map(Yggdrasil.User.BPMapping::getSystem)
			.filter(system -> system.equals('M'))
			.map(value -> SAP.UpdateBillPreference.Request.fromMSSL(request))
			.flatMap(this::sapUpdateBillPreference)
			.switchIfEmpty(sapUpdateBillPreference(SAP.UpdateBillPreference.Request.fromEBS(request)))
			.flatMap(sapResp -> reactiveConnector
				.reactivePost(SKALBOX, SAVE_BILL_PREFERENCE, SAP.UpdateBillPreference.Request.fromEBS(request),
						Boolean.class)
				.doOnError(throwable -> log.error(
						"#updateSubscription :: saveBillPreferences" + " : UserId:[{}] :: Error Occurred :{}",
						request.getUserId(), throwable.getMessage()))
				.onErrorResume(ex -> Mono
					.error(new UbmApiException(UBM_SAVE_BILL_PREFERENCE_ERROR_MSG, UBM_SAVE_BILL_PREFERENCE_ERROR_CODE,
							String.format(BP_NO_S_USER_ID_S, request.getBpNo(), request.getUserId()))))
				.flatMap(savedEntities -> auditService
					.createAudit(EVENT_UPDATE_BILL_PREFERENCE, SOURCE, request, savedEntities, request.getUserId(), "")
					.map(auditRes -> BaseResponse.success())));

	}

	@Override
	public Mono<BaseResponse> delink(Yggdrasil.User.Request request) {
		if (StringUtils.isEmpty(request.getModifiedBy())) {
			return Mono.error(new UbmApiException(UBM_DELINK_MSG, UBM_DELINK_VALIDATION_ERROR_CODE,
					"ModifiedBy cannot be empty"));
		}
		if (StringUtils.isEmpty(request.getIamId())) {
			return Mono
				.error(new UbmApiException(UBM_DELINK_MSG, UBM_DELINK_VALIDATION_ERROR_CODE, "IamId cannot be empty"));
		}
		return Mono.just(request).flatMap(req -> {
			req.setSource('U');
			return reactiveConnector.reactiveDelete(YGGDRASIL_M2M, DELINK, request, Boolean.class)
				.doOnError(throwable -> log.error(ERROR_OCCURRED, throwable.getMessage()))
				.onErrorResume(ex -> Mono.error(new UbmApiException(UBM_DELINK_MSG, UBM_DELINK_ERROR_CODE,
						String.format("ModifiedBy :%s", request.getModifiedBy()))))
				.map(auditRes -> BaseResponse.success());

		});
	}

	private Mono<SAP.RetrieveAccount.Response> retrieveAccountsByBP(List<String> bpNos) {
		return Mono.just(bpNos)
