package io.spdigital.ubm.admin.dto;

import io.spdigital.ubm.util.MaskingUtil;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;
import org.apache.commons.lang3.builder.ToStringBuilder;
import org.apache.commons.lang3.builder.ToStringStyle;

import java.time.LocalDateTime;

@Data
@Builder
@NoArgsConstructor
@AllArgsConstructor
public class GetCustomerResponse {

	private EAccountDetail accountDetail;

	private UtilityAccountDetail utilityAccountDetail;

	private ProfileApiDetails profileApiDetails;

	@Data
	@Builder
	@NoArgsConstructor
	@AllArgsConstructor
	public static class EAccountDetail {

		// E-Account details:

		String userId;

		Character isCompany;

		Character sapSystem;

		IamUser iamUser;

